function ImageUpload({ imagePreviews, existingImagePreviews, showExistingImages, handleImageChange, handleRemoveImage }) {
  return (
    <div>
      <input
        type="file"
        name="images"
        accept="image/*"
        onChange={handleImageChange}
        multiple
      />
      {/* Förhandsgranskningar av nya bilder */}
      {imagePreviews.map((preview, index) => (
        <div key={index}>
          <img
            src={preview}
            alt={`Preview ${index + 1}`}
            style={{ maxWidth: '100px', maxHeight: '100px' }}
          />
          <IconButton onClick={() => handleRemoveImage(index)}>
            <DeleteIcon />
          </IconButton>
        </div>
      ))}
      {/* Förhandsgranskningar av befintliga bilder om showExistingImages är true */}
      {showExistingImages && existingImagePreviews.map((preview, index) => (
        <div key={index}>
          <img
            src={`https://nice-special-meadow.glitch.me/images/${preview}`}
            alt={`Existing Image ${index + 1}`}
            style={{ maxWidth: '100px', maxHeight: '100px' }}
          />
          <IconButton onClick={() => handleRemoveExistingImage(index)}>
            <DeleteIcon />
          </IconButton>
        </div>
      ))}
    </div>
  );
}

export default ImageUpload;
